class ModelDownloader:
    """Downloads pretrained model checkpoints from public repositories."""

    def __init__(self, cache_dir: str = "./model_cache"):
        self.cache_dir = Path(cache_dir)
        self.cache_dir.mkdir(parents=True, exist_ok=True)

    def download_checkpoint(self, url: str, filename: Optional[str] = None) -> str:
        """Download a model checkpoint from a URL."""
        if filename is None:
            filename = url.split("/")[-1]

        filepath = self.cache_dir / filename

        if filepath.exists():
            logger.info(f"Checkpoint already cached at {filepath}")
            return str(filepath)

        logger.info(f"Downloading checkpoint from {url}...")
        try:
            urllib.request.urlretrieve(url, str(filepath))
            logger.info(f"Checkpoint saved to {filepath}")
        except Exception as e:
            logger.error(f"Failed to download checkpoint: {e}")
            raise

        return str(filepath)

    def load_checkpoint(self, url_or_path: str, map_location: str = "cpu") -> Dict[str, Any]:
        """Load a model checkpoint from URL or local path using torch.load."""
        if url_or_path.startswith("http://") or url_or_path.startswith("https://"):
            filepath = self.download_checkpoint(url_or_path)
        else:
            filepath = url_or_path

        logger.info(f"Loading checkpoint from {filepath}...")
        checkpoint = torch.load(filepath, map_location=map_location, weights_only=False)
        logger.info("Checkpoint loaded successfully.")
        return checkpoint

    def load_from_registry(self, model_name: str, map_location: str = "cpu") -> Dict[str, Any]:
        """Load a checkpoint from the model registry by name."""
        if model_name not in MODEL_REGISTRY:
            raise ValueError(
                f"Model '{model_name}' not found in registry. "
                f"Available models: {list(MODEL_REGISTRY.keys())}"
            )
        url = MODEL_REGISTRY[model_name]
        return self.load_checkpoint(url, map_location=map_location)


class CustomImageDataset(Dataset):
    """A custom dataset for demonstration purposes.
    
    In production, replace this with your actual dataset loading logic.
    This generates synthetic data for testing the pipeline.
    """

    def __init__(self, num_samples: int = 1000, num_classes: int = 10,
                 image_size: Tuple[int, int, int] = (3, 224, 224), transform=None):
        self.num_samples = num_samples
        self.num_classes = num_classes
        self.image_size = image_size
        self.transform = transform

        # Generate synthetic data for demonstration
        self.images = torch.randn(num_samples, *image_size)
        self.labels = torch.randint(0, num_classes, (num_samples,))

    def __len__(self):
        return self.num_samples

    def __getitem__(self, idx):
        image = self.images[idx]
        label = self.labels[idx]

        if self.transform:
            image = self.transform(image)

        return image, label


